module traffic_light(
    input rst_n,
    input clk,
    input pass_request,
    output reg red,
    output reg yellow,
    output reg green
);

localparam GREEN_TIME = 60;
localparam YELLOW_TIME = 5;
localparam RED_TIME = 10;

reg [5:0] timer;
reg [1:0] state;

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        timer <= 0;
        state <= 0;
        red <= 0;
        yellow <= 0;
        green <= 1;
    end else begin
        case (state)
            2'b00: begin // Green state
                if (timer == GREEN_TIME - 1) begin
                    state <= 2'b01; // Transition to Yellow state
                    timer <= 0;
                end else begin
                    timer <= timer + 1;
                end
                red <= 0;
                yellow <= 0;
                green <= 1;
            end
            2'b01: begin // Yellow state
                if (timer == YELLOW_TIME - 1) begin
                    state <= 2'b10; // Transition to Red state
                    timer <= 0;
                end else begin
                    timer <= timer + 1;
                end
                red <= 0;
                yellow <= 1;
                green <= 0;
            end
            2'b10: begin // Red state
                if (timer == RED_TIME - 1) begin
                    state <= 2'b00; // Transition to Green state
                    timer <= 0;
                end else begin
                    timer <= timer + 1;
                end
                red <= 1;
                yellow <= 0;
                green <= 0;
            end
            default: begin
                state <= 2'b00; // Default to Green state
            end
        endcase

        if (pass_request && timer > 10) begin
            state <= 2'b01; // Override to Yellow state if button is pressed
            timer <= 0;
        end
    end
end

endmodule
